vec2 my_uv2 = vec2(my_uv.x*my_uv.x - my_uv.y*my_uv.y, 2*my_uv.x*my_uv.y);
my_uv = vec2(my_uv2.x*my_uv.x - my_uv2.y*my_uv.y, my_uv2.x*my_uv.y + my_uv.x*my_uv2.y) + c;

ret.x = 1-texture( sampler_fc_main, my_uv).x;
